// Deduplicar por teléfono y filtrar leads sin teléfono
const items = $input.all();
const seen = new Set();
const leads = [];

for (const item of items) {
  const place = item.json;
  const rawPhone = place.phone || place.phoneUnformatted || '';
  const phone = rawPhone.replace(/\D/g, '');
  if (!phone || phone.length < 10) continue;
  if (seen.has(phone)) continue;
  seen.add(phone);
  leads.push({
    json: {
      name:    place.title || place.name || 'Barbería',
      phone,
      address: place.address || place.street || '',
      city:    place.city || place.neighborhood || '',
      rating:  place.totalScore || place.rating || '',
      url:     place.url || place.website || ''
    }
  });
}

return leads;

